UPDATE movies m JOIN ( SELECT calc.movie_id, calc.new_votes, CASE WHEN calc.new_votes < #{forceUpdateVotesThreshold} OR calc.current_score IS NULL OR ROUND(calc.current_score, 1) <> calc.blended_score THEN calc.blended_score ELSE calc.current_score END AS target_score FROM ( SELECT mv.movie_id, mv.score AS current_score, COALESCE(rs.votes, 0) AS new_votes, ROUND( CASE WHEN COALESCE(rs.votes, 0) = 0 THEN COALESCE(mv.douban_score, mv.score, 0) WHEN mv.douban_score IS NULL THEN COALESCE(rs.avg_rating, 0) * 2 ELSE (#{kWeight} * mv.douban_score + COALESCE(rs.votes, 0) * COALESCE(rs.avg_rating, 0) * 2.0) / (#{kWeight} + COALESCE(rs.votes, 0)) END, 1 ) AS blended_score FROM movies mv LEFT JOIN ( SELECT movie_id, COUNT(*) AS votes, AVG(rating) AS avg_rating FROM ratings WHERE movie_id IN
#{movieId}
GROUP BY movie_id ) rs ON rs.movie_id = mv.movie_id WHERE mv.movie_id IN
#{movieId}
) calc ) c ON c.movie_id = m.movie_id SET m.votes = c.new_votes, m.score = c.target_score WHERE NOT (m.votes <=> c.new_votes AND m.score <=> c.target_score)
